update jst_contest
set audit_status = #{targetAuditStatus},
    update_by = #{updateBy},
    update_time = #{updateTime}

        , remark = #{auditRemark}

where contest_id = #{contestId}
  and audit_status = #{expectedAuditStatus}
  and del_flag = '0'

update jst_contest
set audit_status = #{targetAuditStatus},
    status = #{targetBizStatus},
    update_by = #{updateBy},
    update_time = #{updateTime}
where contest_id = #{contestId}
  and audit_status = #{expectedAuditStatus}
  and status = #{expectedBizStatus}
  and del_flag = '0'

mapper.select:
select c.contest_id AS contestId, c.contest_name AS contestName, c.category AS category, c.group_levels AS groupLevels, c.cover_image AS coverImage, c.price AS price, c.enroll_start_time AS enrollStartTime, c.enroll_end_time AS enrollEndTime, c.audit_status AS auditStatus, c.status AS status, c.partner_id AS partnerId, p.partner_name AS partnerName from jst_contest c left join jst_event_partner p on p.partner_id = c.partner_id and p.del_flag = '0'
c.del_flag = '0'
and c.contest_name like concat('%', #{query.contestName}, '%')
and c.category = #{query.category}
and c.audit_status = #{query.auditStatus}
and c.status = #{query.status}
and c.partner_id = #{query.partnerId}
and c.create_time >= #{query.beginCreateTime}
and c.create_time <= #{query.endCreateTime}
order by c.create_time desc, c.contest_id desc
